const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let input = [];
rl.on('line', (line) => input.push(line)).on('close', () => {
    const T = parseInt(input[0], 10);
    let index = 1;

    for (let t = 0; t < T; t++) {
        let arr = new Array(200).fill(0);
        const n = parseInt(input[index++], 10);
        const numbers = input[index++].split(' ').map(Number);
        arr = arr.fill(0).map((val, i) => (i <= n ? numbers[i - 1] : val));

        let it1 = 1, it2 = n;
        let number = 0;
        let sol = true;

        while (number < 6) {
            number += 1;
            if (arr[it1] !== number || arr[it2] !== number) {
                sol = false;
                break;
            }

            let r1 = 0, r2 = 0;
            while (it1 <= n && arr[it1] === number) {
                r1 += 1;
                it1 += 1;
            }
            while (it2 > 0 && arr[it2] === number) {
                r2 += 1;
                it2 -= 1;
            }
            if (r1 !== r2) {
                sol = false;
                break;
            }
        }

        if (number === 6 && it1 <= it2) {
            number += 1;
            for (let j = it1; j <= it2; j++) {
                if (arr[j] !== 7) {
                    sol = false;
                    break;
                }
            }
        } else {
            sol = false;
        }

        console.log(sol ? "yes" : "no");
    }
});
